    bool obscureText = false,
    bool autocorrect = true,
    SmartDashesType smartDashesType,
    SmartQuotesType smartQuotesType,
    bool enableSuggestions = true,
    bool showCursor,
    bool readOnly,
    ToolbarOptions toolbarOptions,
    bool showSelectionHandles = false,
    EdgeInsets scrollPadding = const EdgeInsets.all(20.0),
    bool enableInteractiveSelection,
    TextSelectionControls selectionControls,
    ScrollController scrollController,
    ScrollPhysics scrollPhysics,
    bool enableIMEPersonalizedLearning,
    VoidCallback onEditingComplete,
    ValueChanged<String> onSubmitted,
    List<TextInputFormatter> inputFormatters,
    bool rendererIgnoresPointer = false,
  }) : super(
          key: key,
          controller: controller,
          focusNode: focusNode,
          style: style,
          cursorColor: cursorColor,
          selectionColor: selectionColor,
          backgroundCursorColor: backgroundColor,
          strutStyle: strutStyle,
          keyboardType: keyboardType,
          textCapitalization: textCapitalization,
          textInputAction: textInputAction,
          textDirection: TextDirection.ltr,
          autofocus: autofocus,
          obscureText: obscureText,
          autocorrect: autocorrect,
          enableSuggestions: enableSuggestions,
          smartDashesType: smartDashesType,
          smartQuotesType: smartQuotesType,
          showCursor: showCursor,
          readOnly: readOnly,
          toolbarOptions: toolbarOptions,
          showSelectionHandles: showSelectionHandles,
          minLines: null,
          maxLines: null,
          expands: false,
          textAlign: TextAlign.start,
          scrollPadding: scrollPadding,
          enableInteractiveSelection: enableInteractiveSelection,
          selectionControls: selectionControls,
          onTap: () => onCursorMove?.call(0),
          onSelectionChanged: onSelectionChange,
          scrollController: scrollController,
          scrollPhysics: scrollPhysics,
          enableIMEPersonalizedLearning: enableIMEPersonalizedLearning,
          onEditingComplete: onEditingComplete,
          onSubmitted: onSubmitted,
          inputFormatters: inputFormatters,
          rendererIgnoresPointer: rendererIgnoresPointer,
        );

  final Function(int) onCursorMove;
  final Function() onSelectionChange;

  @override
  CustomEditableTextState createState() => CustomEditableTextState();
}

class CustomEditableTextState extends EditableTextState {
  @override
  void handleLeftArrow(RawKeyEvent event) {
    widget.onCursorMove(-1);
  }

  @override
  void handleRightArrow(RawKeyEvent event) {
    widget.onCursorMove(1);
  }

  @override
  void onSelectionChanged(TextSelection selection, SelectionChangedCause cause) {
    super.onSelectionChanged(selection, cause);
    widget.onSelectionChange?.call();
  }
}
```

In this custom `EditableText` widget, we override the `handleLeftArrow()` and `handleRightArrow()` functions. These functions move the cursor by one character to the left or right when the corresponding arrow keys are pressed.

We also listen for selection changes with the `onSelectionChanged()` function and call the `onSelectionChange` callback if it's defined.

Using this custom `EditableText` widget, you can move the cursor in a `TextField` widget by a single character in either direction.

To implement this, you can use the custom `CustomEditableText` widget instead of the standard `TextField` widget, and pass in the `onCursorMove` and `onSelectionChange` callbacks. The `onCursorMove` callback should take an integer parameter that's either `1` or `-1`, depending on which arrow key was pressed, and adjust the cursor position of the `TextEditingController` accordingly.

